  // Clock generation
  //----------------------------------------------------------------
  initial begin
    clk = 0;
  end

  always begin
    #CLK_HALF_PERIOD clk = ~clk;
  end

  //----------------------------------------------------------------
  // Task: write_reg
  //----------------------------------------------------------------
  task write_reg;
    input [7:0]  addr;
    input [31:0] data;
    begin
      @(negedge clk);
      cs         = 1;
      we         = 1;
      address    = addr;
      write_data = data;
      @(posedge clk);
      #1;
      cs         = 0;
      we         = 0;
    end
  endtask

  //----------------------------------------------------------------
  // Task: read_reg
  //----------------------------------------------------------------
  task read_reg;
    input  [7:0]  addr;
    output [31:0] data;
    begin
      @(negedge clk);
      cs      = 1;
      we      = 0;
      address = addr;
      @(posedge clk);
      #1;
      data = read_data;
      cs   = 0;
      we   = 0;
    end
  endtask

  //----------------------------------------------------------------
  // Task: wait_ready
  //----------------------------------------------------------------
  task wait_ready;
    reg [31:0] status;
    begin
      status = 32'h0;
      while (!status[0]) begin
        read_reg(ADDR_STATUS, status);
        @(posedge clk);
        #1;
      end
    end
  endtask

  //----------------------------------------------------------------
  // Task: init_key
  //   Loads key and triggers init (key expansion)
  //----------------------------------------------------------------
  task init_key;
    input [127:0] key;
    input         key_length; // 0=128, 1=256
    begin
      // Write config (key length)
      write_reg(ADDR_CONFIG, {31'h0, key_length});

      // Write key words (128-bit key uses KEY0..KEY3; KEY4..KEY7 = 0)
      write_reg(ADDR_KEY0, key[127:96]);
      write_reg(ADDR_KEY1, key[95:64]);
      write_reg(ADDR_KEY2, key[63:32]);
      write_reg(ADDR_KEY3, key[31:0]);
      write_reg(ADDR_KEY4, 32'h0);
      write_reg(ADDR_KEY5, 32'h0);
      write_reg(ADDR_KEY6, 32'h0);
      write_reg(ADDR_KEY7, 32'h0);

      // Assert init
      write_reg(ADDR_CTRL, 32'h1); // init bit
      write_reg(ADDR_CTRL, 32'h0); // deassert

      // Wait for key expansion
      wait_ready();
    end
  endtask

