      write_reg(ADDR_BLOCK1, block[95:64]);
      write_reg(ADDR_BLOCK2, block[63:32]);
      write_reg(ADDR_BLOCK3, block[31:0]);

      // Assert next
      write_reg(ADDR_CTRL, 32'h2); // next bit
      write_reg(ADDR_CTRL, 32'h0); // deassert

      // Wait for result
